def parse_input(filename):
    machines = []
    with open(filename) as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            lights_match = re.search(r'\[([.\#]+)\]', line)
            lights_str = lights_match.group(1)
            target_lights = [1 if c == '#' else 0 for c in lights_str]
            buttons = []
            for m in re.finditer(r'\(([^)]*)\)', line):
                content = m.group(1).strip()
                if content:
                    indices = [int(x) for x in content.split(',')]
                else:
                    indices = []
                buttons.append(indices)
            joltage_match = re.search(r'\{([^}]*)\}', line)
            joltage_str = joltage_match.group(1)
            joltage = [int(x) for x in joltage_str.split(',')]
            machines.append((target_lights, buttons, joltage))
    return machines

def gf2_solve(A, b, n_vars):
    n_eq = len(A)
    rows = []
    for i in range(n_eq):
        row = 0
        for j in range(n_vars):
            if A[i][j]:
                row |= (1 << j)
        if b[i]:
            row |= (1 << n_vars)
        rows.append(row)

    pivot_cols = []
    pivot_row = {}
    col = 0
    row_idx = 0

    while row_idx < len(rows) and col < n_vars:
        found = -1
        for r in range(row_idx, len(rows)):
            if rows[r] & (1 << col):
                found = r
                break
        if found == -1:
            col += 1
            continue
        rows[row_idx], rows[found] = rows[found], rows[row_idx]
        for r in range(len(rows)):
            if r != row_idx and (rows[r] & (1 << col)):
                rows[r] ^= rows[row_idx]
        pivot_cols.append(col)
        pivot_row[col] = row_idx
        row_idx += 1
        col += 1

    for r in range(row_idx, len(rows)):
        if rows[r] == (1 << n_vars):
            return None

    free_vars = [j for j in range(n_vars) if j not in pivot_row]
    n_free = len(free_vars)

    particular = [0] * n_vars
    for pc in pivot_cols:
        ri = pivot_row[pc]
        if rows[ri] & (1 << n_vars):
            particular[pc] = 1

    null_basis = []
    for fv in free_vars:
        vec = [0] * n_vars
        vec[fv] = 1
        for pc in pivot_cols:
            ri = pivot_row[pc]
            if rows[ri] & (1 << fv):
                vec[pc] = 1
        null_basis.append(vec)

    if n_free > 20:
        return sum(particular)

    best = sum(particular)

    for mask in range(1, 1 << n_free):
        x = particular[:]
        for k in range(n_free):
            if mask & (1 << k):
                for j in range(n_vars):
                    x[j] ^= null_basis[k][j]
        w = sum(x)
        if w < best:
            best = w

    return best

